    inline std::vector<int> GetCostumesForCharacter(int characterId) {
        auto it = CHARACTER_COSTUMES.find(characterId);
        if (it != CHARACTER_COSTUMES.end()) {
            return it->second;
        }
        return {};
    }

    inline int GetDefaultCostumeForCharacter(int characterId) {
        auto costumes = GetCostumesForCharacter(characterId);
        return costumes.empty() ? -1 : costumes[0];
    }

    inline std::string FormatCostumeName(int costumeCode, size_t index) {
        return std::string("Costume #") + std::to_string(index + 1);
    }
